import React from 'react';

const ExpiryList = ({ rooms = [] }) => {
    // 1. Собираем все товары из всех комнат в один плоский список
    const allProducts = rooms.flatMap(room =>
        room.inventory.map(item => ({
            ...item,
            roomId: room.id,
            floor: room.floor
        }))
    );

    const today = new Date();
    today.setHours(0, 0, 0, 0);

    // 2. Фильтруем: только товары с датой, которая наступит в ближайшие 90 дней или уже прошла
    const reportItems = allProducts.filter(item => {
        if (!item.expiry) return false;
        const expiryDate = new Date(item.expiry);
        const ninetyDaysFromNow = new Date(today.getTime() + 90 * 24 * 60 * 60 * 1000);

        return expiryDate <= ninetyDaysFromNow;
    }).sort((a, b) => new Date(a.expiry) - new Date(b.expiry)); // Сортируем: сначала самые срочные

    return (
        <div className="page-content fade-in">
            <h2 className="page-title">Контроль сроков (90 дней)</h2>

            <div style={s.statsBar}>
                Найдено позиций: <b>{reportItems.length}</b>
            </div>

            <div className="expiry-table-container">
                <table className="expiry-table">
                    <thead>
                    <tr>
                        <th>Номер</th>
                        <th>Товар</th>
                        <th>Срок годности</th>
                        <th>Статус</th>
                    </tr>
                    </thead>
                    <tbody>
                    {reportItems.map((item, index) => {
                        const expiryDate = new Date(item.expiry);
                        const isExpired = expiryDate < today;

                        return (
                            <tr key={index} style={isExpired ? s.expiredRow : s.warningRow}>
                                <td><b>{item.roomId}</b> <br/><small>Этаж {item.floor}</small></td>
                                <td>{item.name}</td>
                                <td>{new Date(item.expiry).toLocaleDateString()}</td>
                                <td>
                                        <span style={isExpired ? s.expiredBadge : s.warningBadge}>
                                            {isExpired ? 'ПРОСРОЧЕНО' : 'ЗАМЕНИТЬ СКОРО'}
                                        </span>
                                </td>
                            </tr>
                        );
                    })}
                    </tbody>
                </table>

                {reportItems.length === 0 && (
                    <div style={s.emptyState}>
                        <p>На ближайшие 90 дней критических сроков не обнаружено.</p>
                    </div>
                )}
            </div>
        </div>
    );
};

// Внутренние стили для красоты
const s = {
    statsBar: {
        textAlign: 'left',
        fontSize: '12px',
        marginBottom: '15px',
        color: '#666',
        borderLeft: '3px solid #c5a059',
        paddingLeft: '10px'
    },
    expiredRow: { backgroundColor: '#fff1f0' },
    warningRow: { backgroundColor: '#fffbe6' },
    expiredBadge: {
        backgroundColor: '#ff4d4f',
        color: 'white',
        fontSize: '10px',
        padding: '2px 6px',
        borderRadius: '4px',
        fontWeight: 'bold'
    },
    warningBadge: {
        backgroundColor: '#faad14',
        color: 'white',
        fontSize: '10px',
        padding: '2px 6px',
        borderRadius: '4px',
        fontWeight: 'bold'
    },
    emptyState: {
        marginTop: '60px',
        color: '#999',
        textAlign: 'center'
    }
};

export default ExpiryList;
